class _Node:
    def __init__(self, val):
        self.val = val
        self.next = None


class MyLinkedList:
    def __init__(self):
        self.head = _Node(0)
        self.size = 0
    def get(self, index):
        if index < 0 or index >= self.size:
            return -1
        cur = self.head.next
        for _ in range(index):
            cur = cur.next
        return cur.val
    def addAtIndex(self, index, val):
        if index > self.size:
            return
        if index < 0:
            index = 0
        prev = self.head
        for _ in range(index):
            prev = prev.next
        node = _Node(val)
        node.next = prev.next
        prev.next = node
        self.size += 1
    def addAtHead(self, val):
        self.addAtIndex(0, val)
    def addAtTail(self, val):
        self.addAtIndex(self.size, val)
    def deleteAtIndex(self, index):
        if index < 0 or index >= self.size:
            return
        prev = self.head
        for _ in range(index):
            prev = prev.next
        prev.next = prev.next.next
        self.size -= 1

